const authData = $input.item.json;
const body = authData.body || {};

return {
  json: {
    campaign_id: body.campaign_id || '',
    week_number: parseInt(body.week_number) || 1,
    user_id: authData.user_id || ''
  }
};

const params = $('Extract Params').item.json;
const icpRaw = $('Read ICP').item.json;
const productsRaw = $('Read Products').item.json;

// Parse ICP
let icp = {};
try {
  icp = Array.isArray(icpRaw) ? icpRaw[0] || {} : icpRaw || {};
} catch(e) { icp = {}; }

// Parse products
let products = [];
try {
  products = Array.isArray(productsRaw) ? productsRaw : [];
} catch(e) { products = []; }

const productsList = products.map(p => p.name + ' (' + (p.category || 'General') + '): ' + (p.description || '')).join('\n');

const weekNum = params.week_number;
const dayNames = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday'];

const body = JSON.stringify({
  model: 'claude-sonnet-4-20250514',
  max_tokens: 4096,
  system: 'You are a luxury brand social media content strategist specializing in the 7-Day Storytelling Framework. Generate daily topics that follow the weekly narrative arc.',
  messages: [{
    role: 'user',
    content: 'Generate 7 daily social media content topics for WEEK ' + weekNum + ' of a monthly campaign.\n\nBUSINESS CONTEXT:\n- Industry: ' + (icp.industry || 'General') + '\n- Target Audience: ' + (icp.target_audience || icp.demographics || 'General audience') + '\n- Brand Voice: ' + (icp.brand_voice || icp.tone || 'Professional and engaging') + '\n- Content Pillars: ' + JSON.stringify(icp.content_pillars || []) + '\n- Pain Points: ' + JSON.stringify(icp.pain_points || []) + '\n\nPRODUCTS/SERVICES:\n' + (productsList || 'No specific products listed') + '\n\n7-DAY STORYTELLING FRAMEWORK (MANDATORY - each day MUST follow its assigned theme):\nDay 1 (Monday): CURIOSITY HOOK — Stop the scroll with intrigue and visual mystery. Tease a product detail, an unseen angle, or a surprising fact that makes viewers need to know more.\nDay 2 (Tuesday): CRAFTSMANSHIP — Establish luxury credibility and authority. Showcase the making process, materials, skill, or heritage behind the product.\nDay 3 (Wednesday): MEANING & SYMBOLISM — Build emotional connection. Explore what the product represents—love, achievement, identity, tradition.\nDay 4 (Thursday): TRANSFORMATION MOMENT — Show the impact when the product is worn/used. Before-and-after energy, confidence shift, special occasion moments.\nDay 5 (Friday): HIDDEN DETAIL / SURPRISE — Encourage shares through discovery. Reveal a detail most people miss, an Easter egg, or an unexpected feature.\nDay 6 (Saturday): LIFESTYLE ASPIRATION — Inspire desire and aspiration. Show the life, setting, and experiences associated with the product.\nDay 7 (Sunday): LEGACY & TIMELESSNESS — Build brand prestige. Highlight heritage, generational stories, and enduring value.\n\nIMPORTANT RULES:\n- Each day MUST reference a UNIQUE product from the products list above (no repeats within the week)\n- The topic and description must clearly embody the assigned storytelling theme\n- Content angles should be specific to the theme (not generic)\n\nFor each of the 7 days provide:\n1. topic: A compelling topic title that reflects the day\'s storytelling theme (max 60 chars)\n2. description: Brief description of the post angle tied to the theme (max 150 chars)\n3. content_angle: Specific approach for this theme (e.g., for Curiosity: "Macro Tease", "Shadow Reveal", "Question Hook"; for Craftsmanship: "Workshop Tour", "Material Spotlight", "Artisan Profile")\n4. product_name: Name of a UNIQUE product from the list above to feature\n5. storytelling_theme: The theme name (curiosity_hook, craftsmanship, meaning_symbolism, transformation, hidden_detail, lifestyle_aspiration, legacy_timelessness)\n\nWeek ' + weekNum + ' should feel fresh and distinct from other weeks while maintaining the framework.\n\n' + (params.storytelling_framework ? 'ADDITIONAL CONTEXT FROM FRONTEND:\n' + params.storytelling_framework + '\n\n' : '') + 'Return ONLY a valid JSON array of 7 objects with keys: day_number (1-7), topic, description, content_angle, product_name, storytelling_theme. No markdown.'
  }]
});

return {
  json: {
    apiBody: body,
    user_id: params.user_id,
    campaign_id: params.campaign_id,
    week_number: weekNum,
    products: products
  }
};

const input = $input.item.json;
const prepData = $('Prepare Claude Prompt').item.json;

let raw = '';
try {
  raw = input.content[0].text;
} catch(e) { raw = '[]'; }

let topics = [];
try {
  topics = JSON.parse(raw);
} catch(e) {
  const stripped = raw.replace(/```(?:json)?\s*/g, '').replace(/```\s*$/g, '').trim();
  try { topics = JSON.parse(stripped); } catch(e2) {
    const match = stripped.match(/\[[\s\S]*\]/);
    if (match) { try { topics = JSON.parse(match[0]); } catch(e3) { topics = []; } }
  }
}

if (!Array.isArray(topics)) topics = [];

// Map product_name to product_id
const products = prepData.products || [];
const mapped = topics.slice(0, 7).map((t, i) => {
  let productId = null;
  let productName = t.product_name || null;
  if (productName) {
    const match = products.find(p => p.name.toLowerCase() === productName.toLowerCase());
    if (match) productId = match.id;
  }
  return {
    user_id: prepData.user_id,
    campaign_id: prepData.campaign_id,
    week_number: prepData.week_number,
    day_number: t.day_number || (i + 1),
    topic: (t.topic || 'Topic ' + (i + 1)).substring(0, 255),
    description: (t.description || '').substring(0, 500),
    content_angle: (t.content_angle || 'General').substring(0, 100),
    product_id: productId,
    product_name: productName,
    status: 'pending'
  };
});

return {
  json: {
    topics: mapped,
    topics_body: JSON.stringify(mapped),
    user_id: prepData.user_id,
    campaign_id: prepData.campaign_id,
    week_number: prepData.week_number
  }
};

const saved = $input.item.json;
const parseData = $('Parse Topics').item.json;

// Return the saved topics (or original if save didn't return them)
let topics = [];
try {
  topics = Array.isArray(saved) ? saved : parseData.topics;
} catch(e) {
  topics = parseData.topics;
}

return {
  json: {
    success: true,
    topics: topics,
    week_number: parseData.week_number,
    campaign_id: parseData.campaign_id
  }
};
